//! GKQ v2 backend.
//!
//! Reads a `GKQ2` magic-byte file (see `distributed-inference/gkq_v2_format.py`
//! for the canonical byte-level spec) and exposes the reconstructed tensors
//! through the `WeightBackend` trait so `KnotWeights::load_mmap` can route
//! to it transparently.
//!
//! Each spectral block (U, σ, Vᵀ) is delta-decoded, dequantized to f32, and
//! reconstructed via `W = U @ diag(σ) @ Vᵀ` at load time. The resulting f32
//! payload is held in `OwnedBytes::Owned(Arc<Vec<u8>>)` so the rest of the
//! pipeline reads it the same way it reads native fp32 tensors. Dense blocks
//! are passed through verbatim (and alias blocks are resolved to share their
//! target's `Arc<Vec<u8>>` so tied embeddings cost zero extra bytes).
//!
//! Quant formula (must match the Python encoder in `encode-real-model.py`):
//!   U  : f32 x = ((q - 128) / 127) * u_max     (signed-uint8 offset)
//!   Vᵀ : f32 x = ((q - 128) / 127) * v_max     (signed-uint8 offset)
//!   σ  : f32 x = (q / 255) * sigma_max         (UNSIGNED uint8)
//!
//! Delta decode (per byte stream): out[0]=delta[0]; out[i] = prev.wrapping_add(delta[i]).

#![cfg(not(target_arch = "wasm32"))]

use std::collections::HashMap;
use std::fs::File;
use std::io::Read;
use std::num::NonZeroUsize;
use std::sync::Arc;

use lru::LruCache;
use memmap2::Mmap;
use parking_lot::Mutex;

use crate::loader::{KnotConfig, OwnedBytes, TensorInfo, WeightBackend};
use crate::math::{dequantize_q4k_row, f16_to_f32};

/// Default LRU cache size for reconstructed spectral tensors (bytes).
/// Override with `GKQ_RECONSTRUCT_CACHE_BYTES` env var.
/// 8 GB default keeps ~8-16 reconstructed Llama-70B FFN tensors hot at once
/// while bounding total RSS, leaving ~30 GB headroom on a 64 GB workstation
/// for the model's KV-cache, scratch buffers, and the dense tensors which are
/// always-resident.
const DEFAULT_RECONSTRUCT_CACHE_BYTES: usize = 8 * 1024 * 1024 * 1024;

// ─── Constants mirroring gkq_v2_format.py ───────────────────────────────────

const MAGIC: &[u8; 4] = b"GKQ2";
// v3 bumps dense-block byte_length from u32 to u64 so individual dense
// tensors >= 4 GiB (Qwen2.5-72B token_embd.weight = 4.98 GiB f32) encode
// without truncation. Reader accepts both versions.
const SUPPORTED_READ_VERSIONS: &[u8] = &[2, 3];

const DENSE_FLAG_ALIAS: u8 = 0x01;

const DTYPE_F32: u8 = 0;
const DTYPE_F16: u8 = 1;
const DTYPE_Q4_K: u8 = 2;
const DTYPE_Q6_K: u8 = 3;
const DTYPE_Q8: u8 = 4;

fn tensor_type_from_code(code: u8) -> &'static str {
    match code {
        DTYPE_F32 => "F32",
        DTYPE_F16 => "F16",
        DTYPE_Q4_K => "Q4_K",
        DTYPE_Q6_K => "Q6_K",
        DTYPE_Q8 => "Q8",
        _ => "F32",
    }
}

// ─── Name translation: encoder → model.rs canonical ─────────────────────────

/// The Python encoder emits GGUF-style dot names — but with `attn_o.weight`
/// where the rest of the Rust pipeline (via `resolve_tensor`'s GGUF fallback)
/// expects `attn_output.weight`. Translate at load time so we don't have to
/// regenerate every existing GKQ knot on disk.
///
/// All other names (`blk.N.attn_q.weight`, `blk.N.ffn_gate.weight`,
/// `token_embd.weight`, `output_norm.weight`, `output.weight`, etc.) already
/// match what `resolve_tensor`'s underscore-to-dot fallback table accepts, so
/// we pass them through untouched.
fn translate_name(raw: &str) -> String {
    // `blk.N.attn_o.weight` → `blk.N.attn_output.weight`
    // (use a literal substring swap because we know the exact emit shape).
    if raw.contains(".attn_o.weight") {
        return raw.replace(".attn_o.weight", ".attn_output.weight");
    }
    if raw.contains(".attn_o.bias") {
        return raw.replace(".attn_o.bias", ".attn_output.bias");
    }
    raw.to_string()
}

// ─── Cursor over the mmap'd file ────────────────────────────────────────────

struct Cursor<'a> {
    buf: &'a [u8],
    pos: usize,
}

impl<'a> Cursor<'a> {
    fn new(buf: &'a [u8]) -> Self {
        Self { buf, pos: 0 }
    }

    fn read_slice(&mut self, n: usize) -> Result<&'a [u8], String> {
        if self.pos + n > self.buf.len() {
            return Err(format!(
                "GkqBackend: short read (need {} bytes at offset {}, file size {})",
                n,
                self.pos,
                self.buf.len()
            ));
        }
        let out = &self.buf[self.pos..self.pos + n];
        self.pos += n;
        Ok(out)
    }

    fn read_u8(&mut self) -> Result<u8, String> {
        Ok(self.read_slice(1)?[0])
    }

    fn read_u16(&mut self) -> Result<u16, String> {
        let s = self.read_slice(2)?;
        Ok(u16::from_le_bytes([s[0], s[1]]))
    }

    fn read_u32(&mut self) -> Result<u32, String> {
        let s = self.read_slice(4)?;
        Ok(u32::from_le_bytes([s[0], s[1], s[2], s[3]]))
    }

    fn read_u64(&mut self) -> Result<u64, String> {
        let s = self.read_slice(8)?;
        Ok(u64::from_le_bytes([
            s[0], s[1], s[2], s[3], s[4], s[5], s[6], s[7],
        ]))
    }

    fn read_f32(&mut self) -> Result<f32, String> {
        let s = self.read_slice(4)?;
        Ok(f32::from_le_bytes([s[0], s[1], s[2], s[3]]))
    }

    fn read_string(&mut self, n: usize) -> Result<String, String> {
        let s = self.read_slice(n)?;
        std::str::from_utf8(s)
            .map(|x| x.to_string())
            .map_err(|e| format!("GkqBackend: bad utf-8: {}", e))
    }
}

// ─── Codec helpers ──────────────────────────────────────────────────────────

/// Delta-decode a uint8 byte stream in place (cumulative sum mod 256).
fn delta_decode(buf: &[u8]) -> Vec<u8> {
    let mut out = vec![0u8; buf.len()];
    if buf.is_empty() {
        return out;
    }
    out[0] = buf[0];
    let mut prev = buf[0];
    for i in 1..buf.len() {
        prev = prev.wrapping_add(buf[i]);
        out[i] = prev;
    }
    out
}

/// Dequantize the signed-uint8 (offset-128) representation used for U and Vᵀ.
#[inline]
fn dequant_signed(q: u8, max: f32) -> f32 {
    ((q as f32) - 128.0) / 127.0 * max
}

/// Dequantize the unsigned-uint8 representation used for σ.
#[inline]
fn dequant_unsigned(q: u8, max: f32) -> f32 {
    (q as f32) / 255.0 * max
}

/// `W = U @ diag(σ) @ Vᵀ`, written as a [d_out, d_in] row-major f32 buffer.
///
/// Fast path uses `matrixmultiply::sgemm` (cache-blocked, pure-Rust kernel,
/// ~10× faster than naive scalar at d_in ≥ 1024). We first fold σ into U
/// row-wise so the matmul itself is a plain `U_scaled @ Vᵀ`.
fn reconstruct_matrix(
    u: &[f32],
    sigma: &[f32],
    vt: &[f32],
    d_out: usize,
    rank: usize,
    d_in: usize,
) -> Vec<f32> {
    // Fold sigma into U row-wise: U_scaled[i, k] = U[i, k] * sigma[k].
    // Cheap O(d_out * rank) pass.
    let mut u_scaled = u.to_vec();
    for i in 0..d_out {
        let row = &mut u_scaled[i * rank..(i + 1) * rank];
        for k in 0..rank {
            row[k] *= sigma[k];
        }
    }

    let mut w = vec![0f32; d_out * d_in];

    // matrixmultiply::sgemm signature:
    //   sgemm(m, k, n, alpha, a, rsa, csa, b, rsb, csb, beta, c, rsc, csc)
    // means: C[m,n] = alpha * A[m,k] @ B[k,n] + beta * C
    // Our A=U_scaled is [d_out, rank] row-major: rsa=rank, csa=1
    // Our B=Vᵀ        is [rank, d_in]   row-major: rsb=d_in, csb=1
    // Our C=W         is [d_out, d_in]  row-major: rsc=d_in, csc=1
    unsafe {
        matrixmultiply::sgemm(
            d_out,
            rank,
            d_in,
            1.0,
            u_scaled.as_ptr(),
            rank as isize,
            1,
            vt.as_ptr(),
            d_in as isize,
            1,
            0.0,
            w.as_mut_ptr(),
            d_in as isize,
            1,
        );
    }
    w
}

/// Pack a `&[f32]` into a `Vec<u8>` (little-endian, host-native on every
/// target we care about; verified by `bytemuck`'s POD bounds elsewhere).
fn f32s_to_bytes(floats: &[f32]) -> Vec<u8> {
    let mut out = Vec::with_capacity(floats.len() * 4);
    for &f in floats {
        out.extend_from_slice(&f.to_le_bytes());
    }
    out
}

// ─── Backend ────────────────────────────────────────────────────────────────

/// Raw spectral block — kept in compressed form. Reconstruction
/// (delta-decode + dequant + sgemm) deferred to first `fetch_tensor`
/// call and cached LRU.
struct SpectralRaw {
    u_q8: Vec<u8>,
    sigma_q8: Vec<u8>,
    v_q8: Vec<u8>,
    u_max: f32,
    sigma_max: f32,
    v_max: f32,
    d_out: usize,
    d_in: usize,
    rank: usize,
}

impl SpectralRaw {
    /// Bytes the reconstructed tensor will occupy as f32. Used to bound
    /// the LRU cache and to report TensorInfo.length without reconstructing.
    fn reconstructed_bytes(&self) -> usize {
        self.d_out * self.d_in * 4
    }

    /// Do the actual delta-decode + dequant + sgemm. ~100ms-2s per tensor
    /// at Llama-70B scale; near-zero at 0.5B scale.
    fn reconstruct(&self) -> Vec<u8> {
        let u_q = delta_decode(&self.u_q8);
        let s_q = delta_decode(&self.sigma_q8);
        let v_q = delta_decode(&self.v_q8);

        let mut u = vec![0f32; self.d_out * self.rank];
        for i in 0..u.len() {
            u[i] = dequant_signed(u_q[i], self.u_max);
        }
        let mut sigma = vec![0f32; self.rank];
        for i in 0..self.rank {
            sigma[i] = dequant_unsigned(s_q[i], self.sigma_max);
        }
        let mut vt = vec![0f32; self.rank * self.d_in];
        for i in 0..vt.len() {
            vt[i] = dequant_signed(v_q[i], self.v_max);
        }

        let w = reconstruct_matrix(&u, &sigma, &vt, self.d_out, self.rank, self.d_in);
        f32s_to_bytes(&w)
    }
}

/// Companion residual to a spectral tensor — stores the dequantized delta
/// R = W - U_K·diag(σ_K)·V_K^T as raw bytes plus the dtype/dims needed to
/// dequantize at fetch time. Created by encode-hybrid.py for every spectral
/// twin, stored under name `<canonical>__residual`. The hybrid fetch path
/// (LoRA-inverse style) reads the spectral half, dequantizes the residual,
/// and elementwise-adds before serving the f32 reconstruction.
struct ResidualEntry {
    raw: Vec<u8>,
    dtype_code: u8,
    d_out: usize,
    d_in: usize,
}

/// Suffix that marks a dense tensor as the residual twin of a spectral tensor.
const RESIDUAL_SUFFIX: &str = "__residual";

pub struct GkqBackend {
    /// Always-resident dense tensors (embeddings, norms, lm_head, biases).
    /// These are already-decoded bytes; passed through verbatim. Aliases share
    /// the underlying `Arc<Vec<u8>>`.
    dense_tensors: HashMap<String, Arc<Vec<u8>>>,
    /// Spectral tensors held in compressed form. Materialized on demand.
    spectral_raw: HashMap<String, SpectralRaw>,
    /// Residual companions keyed by their target spectral name (NOT by the
    /// on-disk `__residual` suffix). On hybrid knots this map is non-empty;
    /// on legacy pure-spectral knots it stays empty and the fetch path
    /// degenerates to the original GKQ rank-K-only behavior.
    residuals: HashMap<String, ResidualEntry>,
    /// LRU cache of reconstructed (spectral + residual) bytes, bounded by
    /// total bytes. `Mutex<...>` because `WeightBackend::fetch_tensor` takes
    /// `&self`.
    reconstruct_cache: Mutex<ReconstructCache>,
    pub metadata_map: HashMap<String, TensorInfo>,
    pub config: Option<KnotConfig>,
}

struct ReconstructCache {
    /// Round-robin LRU. Keyed by tensor name, value is the reconstructed bytes.
    inner: LruCache<String, Arc<Vec<u8>>>,
    /// Running total of bytes held. Used for eviction below the byte budget.
    bytes_used: usize,
    /// Hard ceiling. When `bytes_used > byte_budget` we pop LRU until under.
    byte_budget: usize,
}

impl ReconstructCache {
    fn new(byte_budget: usize) -> Self {
        Self {
            // Entry cap intentionally generous (1M); we evict by bytes below.
            // usize::MAX would overflow hashbrown's capacity calc.
            inner: LruCache::new(NonZeroUsize::new(1_000_000).unwrap()),
            bytes_used: 0,
            byte_budget,
        }
    }

    fn get(&mut self, name: &str) -> Option<Arc<Vec<u8>>> {
        self.inner.get(name).cloned()
    }

    fn put(&mut self, name: String, bytes: Arc<Vec<u8>>) {
        let n = bytes.len();
        if let Some(old) = self.inner.put(name, bytes) {
            self.bytes_used = self.bytes_used.saturating_sub(old.len());
        }
        self.bytes_used += n;
        // Evict LRU until under budget. Don't evict the entry we just inserted
        // (it's the MRU so pop_lru() will skip it).
        while self.bytes_used > self.byte_budget {
            match self.inner.pop_lru() {
                Some((_, dropped)) => {
                    self.bytes_used = self.bytes_used.saturating_sub(dropped.len())
                }
                None => break,
            }
        }
    }
}

impl GkqBackend {
    pub fn load(path: &str) -> Result<Self, String> {
        let file = File::open(path).map_err(|e| format!("GkqBackend: open {}: {}", path, e))?;
        // Mmap so large knots (hundreds of MB) don't double-buffer on load,
        // but copy out into owned Arcs because reconstruct allocates anyway
        // and we want the mmap droppable after load_v2 returns.
        let mmap = unsafe { Mmap::map(&file).map_err(|e| format!("GkqBackend: mmap: {}", e))? };
        let buf: &[u8] = &mmap;

        let mut cur = Cursor::new(buf);

        // ── Header ─────────────────────────────────────────────────────────
        let magic = cur.read_slice(4)?;
        if magic != MAGIC {
            return Err(format!(
                "GkqBackend: bad magic at {}: expected {:?}, got {:?}",
                path, MAGIC, magic
            ));
        }
        let version = cur.read_u8()?;
        if !SUPPORTED_READ_VERSIONS.contains(&version) {
            return Err(format!(
                "GkqBackend: unsupported header_version={} (supported: {:?})",
                version, SUPPORTED_READ_VERSIONS
            ));
        }

        let model_name_len = cur.read_u16()? as usize;
        let _model_name = cur.read_string(model_name_len)?;

        let arch_len = cur.read_u16()? as usize;
        let _arch = cur.read_string(arch_len)?;

        let meta_len = cur.read_u32()? as usize;
        let meta_str = cur.read_string(meta_len)?;
        let metadata_val: serde_json::Value = serde_json::from_str(&meta_str)
            .map_err(|e| format!("GkqBackend: metadata json: {}", e))?;

        // Best-effort: deserialize the JSON dict directly into KnotConfig.
        // Unknown fields (`tie_word_embeddings`, etc.) get dropped silently
        // by serde, matching the behavior of `parse_config` on KNOT files.
        let config: Option<KnotConfig> = serde_json::from_value(metadata_val.clone()).ok();
        if config.is_none() {
            eprintln!(
                "[GkqBackend] WARNING: failed to deserialize KnotConfig from GKQ metadata; \
                 falling back to None (TinyLlama defaults will apply): metadata={}",
                meta_str
            );
        }

        let num_spectral = cur.read_u32()? as usize;
        let num_dense = cur.read_u32()? as usize;

        eprintln!(
            "[GkqBackend] loading {}: model_name={:?} arch={:?} spectral={} dense={}",
            path, _model_name, _arch, num_spectral, num_dense
        );

        let mut spectral_raw: HashMap<String, SpectralRaw> = HashMap::new();
        let mut dense_tensors: HashMap<String, Arc<Vec<u8>>> = HashMap::new();
        let mut residuals: HashMap<String, ResidualEntry> = HashMap::new();
        let mut metadata_map: HashMap<String, TensorInfo> = HashMap::new();
        // Aliases recorded in pass 1, resolved in pass 2.
        let mut pending_aliases: Vec<(String, String)> = Vec::new();

        // ── Spectral blocks (DEFERRED RECONSTRUCTION) ────────────────────
        // We just parse + delta-encoded byte storage; the actual sgemm waits
        // for first fetch_tensor. Boot time was 6+ hours for Llama-70B in
        // eager mode; now it's seconds (just byte copying out of mmap).
        let t_spectral = std::time::Instant::now();
        for _ in 0..num_spectral {
            let name_len = cur.read_u16()? as usize;
            let raw_name = cur.read_string(name_len)?;
            let name = translate_name(&raw_name);

            let d_out = cur.read_u32()? as usize;
            let d_in = cur.read_u32()? as usize;
            let rank = cur.read_u16()? as usize;
            let u_max = cur.read_f32()?;
            let sigma_max = cur.read_f32()?;
            let v_max = cur.read_f32()?;

            let u_bytes = cur.read_slice(d_out * rank)?.to_vec();
            let sigma_bytes = cur.read_slice(rank)?.to_vec();
            let v_bytes = cur.read_slice(rank * d_in)?.to_vec();

            let raw = SpectralRaw {
                u_q8: u_bytes,
                sigma_q8: sigma_bytes,
                v_q8: v_bytes,
                u_max,
                sigma_max,
                v_max,
                d_out,
                d_in,
                rank,
            };

            metadata_map.insert(
                name.clone(),
                TensorInfo {
                    offset: 0,
                    length: raw.reconstructed_bytes() as u64,
                    tensor_type: "F32".to_string(),
                    shape: None,
                },
            );
            spectral_raw.insert(name, raw);
        }
        eprintln!(
            "[GkqBackend] parsed {} spectral blocks (deferred reconstruct) in {} ms",
            num_spectral,
            t_spectral.elapsed().as_millis()
        );

        // ── Dense blocks (always resident) ───────────────────────────────
        for _ in 0..num_dense {
            let name_len = cur.read_u16()? as usize;
            let raw_name = cur.read_string(name_len)?;
            let name = translate_name(&raw_name);

            let flags = cur.read_u8()?;
            if flags & DENSE_FLAG_ALIAS != 0 {
                let tgt_len = cur.read_u16()? as usize;
                let raw_target = cur.read_string(tgt_len)?;
                let target = translate_name(&raw_target);
                pending_aliases.push((name, target));
                continue;
            }

            let dtype_code = cur.read_u8()?;
            let rank = cur.read_u8()? as usize;
            let mut dims = Vec::with_capacity(rank);
            for _ in 0..rank {
                dims.push(cur.read_u32()? as usize);
            }
            // v2: u32 byte_length (4 GiB cap); v3: u64 byte_length
            let byte_length = if version <= 2 {
                cur.read_u32()? as usize
            } else {
                cur.read_u64()? as usize
            };
            let raw = cur.read_slice(byte_length)?.to_vec();

            // Hybrid LoRA-inverse residual companion: any tensor named
            // "<spectral_name>__residual" is stashed as a ResidualEntry against
            // the bare spectral name. It is NOT exposed as a separately
            // fetchable tensor (would otherwise be served as opaque Q4_K/F16
            // bytes the consumer doesn't know how to interpret); instead
            // fetch_tensor on the bare name will dequantize + add it to the
            // spectral reconstruction.
            if let Some(spec_name) = name.strip_suffix(RESIDUAL_SUFFIX) {
                // 2-D residual; for non-spectral dims we fall back to using
                // d_out=dims[0], d_in=product(dims[1..]) (defensive — should
                // always be exactly 2-D from the encoder).
                let (d_out, d_in) = if dims.len() == 2 {
                    (dims[0], dims[1])
                } else if dims.len() == 1 {
                    (1, dims[0])
                } else {
                    let do_ = dims[0];
                    let di_ = dims[1..].iter().product::<usize>();
                    (do_, di_)
                };
                residuals.insert(
                    spec_name.to_string(),
                    ResidualEntry {
                        raw,
                        dtype_code,
                        d_out,
                        d_in,
                    },
                );
                // Don't register the __residual name in metadata_map: callers
                // only ever ask for the bare spectral name.
                continue;
            }

            let arc = Arc::new(raw);
            let byte_len = arc.len() as u64;
            metadata_map.insert(
                name.clone(),
                TensorInfo {
                    offset: 0,
                    length: byte_len,
                    tensor_type: tensor_type_from_code(dtype_code).to_string(),
                    shape: None,
                },
            );
            dense_tensors.insert(name, arc);
        }

        // ── Resolve aliases (second pass) ─────────────────────────────────
        for (alias_name, target_name) in pending_aliases {
            let target_arc = dense_tensors.get(&target_name).cloned().ok_or_else(|| {
                format!(
                    "GkqBackend: dense alias '{}' points to unknown target '{}'",
                    alias_name, target_name
                )
            })?;
            let target_info = metadata_map
                .get(&target_name)
                .cloned()
                .unwrap_or(TensorInfo {
                    offset: 0,
                    length: target_arc.len() as u64,
                    tensor_type: "F32".to_string(),
                    shape: None,
                });
            dense_tensors.insert(alias_name.clone(), target_arc);
            metadata_map.insert(alias_name, target_info);
        }

        // Drop the mmap explicitly so the underlying file handle releases.
        drop(mmap);

        // Cache size: env override > default.
        let cache_budget = std::env::var("GKQ_RECONSTRUCT_CACHE_BYTES")
            .ok()
            .and_then(|s| s.parse::<usize>().ok())
            .unwrap_or(DEFAULT_RECONSTRUCT_CACHE_BYTES);
        eprintln!(
            "[GkqBackend] ready: spectral={} residual={} dense={} cache_budget={} MiB",
            spectral_raw.len(),
            residuals.len(),
            dense_tensors.len(),
            cache_budget / (1024 * 1024)
        );

        Ok(Self {
            dense_tensors,
            spectral_raw,
            residuals,
            reconstruct_cache: Mutex::new(ReconstructCache::new(cache_budget)),
            metadata_map,
            config,
        })
    }
}

/// Dequantize a residual `ResidualEntry` into a `Vec<f32>` of length
/// `d_out * d_in`. Supports F32 (bytewise reinterpret), F16 (per-element
/// f16→f32), and Q4_K (per-row dequant via the shared
/// `crate::math::dequantize_q4k_row` kernel).
fn dequantize_residual(r: &ResidualEntry) -> Result<Vec<f32>, String> {
    let total = r.d_out * r.d_in;
    match r.dtype_code {
        DTYPE_F32 => {
            if r.raw.len() != total * 4 {
                return Err(format!(
                    "residual F32 byte length mismatch: got {}, expected {} ({}×{}×4)",
                    r.raw.len(),
                    total * 4,
                    r.d_out,
                    r.d_in
                ));
            }
            let mut out = vec![0f32; total];
            for i in 0..total {
                let off = i * 4;
                out[i] = f32::from_le_bytes([
                    r.raw[off],
                    r.raw[off + 1],
                    r.raw[off + 2],
                    r.raw[off + 3],
                ]);
            }
            Ok(out)
        }
        DTYPE_F16 => {
            if r.raw.len() != total * 2 {
                return Err(format!(
                    "residual F16 byte length mismatch: got {}, expected {} ({}×{}×2)",
                    r.raw.len(),
                    total * 2,
                    r.d_out,
                    r.d_in
                ));
            }
            let mut out = vec![0f32; total];
            for i in 0..total {
                let off = i * 2;
                let bits = u16::from_le_bytes([r.raw[off], r.raw[off + 1]]);
                out[i] = f16_to_f32(bits);
            }
            Ok(out)
        }
        DTYPE_Q4_K => {
            if !r.d_in.is_multiple_of(256) {
                return Err(format!(
                    "residual Q4_K requires d_in % 256 == 0; got d_in={}",
                    r.d_in
                ));
            }
            let bytes_per_row = (r.d_in / 256) * 144;
            let expected = r.d_out * bytes_per_row;
            if r.raw.len() != expected {
                return Err(format!(
                    "residual Q4_K byte length mismatch: got {}, expected {} ({}×{} blocks×144)",
                    r.raw.len(),
                    expected,
                    r.d_out,
                    r.d_in / 256
                ));
            }
            let mut out = vec![0f32; total];
            for row_idx in 0..r.d_out {
                let off = row_idx * r.d_in;
                dequantize_q4k_row(&mut out[off..off + r.d_in], &r.raw, row_idx, r.d_in);
            }
            Ok(out)
        }
        other => Err(format!(
            "residual dtype {} not supported (expected F32=0 / F16=1 / Q4_K=2)",
            other
        )),
    }
}

impl GkqBackend {
    /// Reconstruct a spectral tensor and, if a hybrid residual companion
    /// exists under `<name>__residual`, dequantize it and elementwise-add
    /// to land at W' = U·diag(σ)·Vᵀ + dequant(R). The combined bytes are
    /// what gets cached and served. On legacy pure-spectral knots (no
    /// residual map entry) this reduces to the original rank-K behavior.
    fn reconstruct_with_residual(&self, name: &str, raw: &SpectralRaw) -> Result<Vec<u8>, String> {
        // Spectral bytes (f32 row-major [d_out * d_in])
        let spectral_bytes = raw.reconstruct();
        let n_f32 = raw.d_out * raw.d_in;

        // No residual companion → pass spectral through (legacy pure-spectral
        // GKQ knot).
        let Some(resid) = self.residuals.get(name) else {
            return Ok(spectral_bytes);
        };

        if resid.d_out != raw.d_out || resid.d_in != raw.d_in {
            return Err(format!(
                "GkqBackend: residual shape ({}×{}) does not match spectral ({}×{}) for '{}'",
                resid.d_out, resid.d_in, raw.d_out, raw.d_in, name
            ));
        }

        let t_dq = std::time::Instant::now();
        let resid_f32 = dequantize_residual(resid)?;
        if resid_f32.len() != n_f32 {
            return Err(format!(
                "GkqBackend: residual dequant length {} ≠ spectral {} for '{}'",
                resid_f32.len(),
                n_f32,
                name
            ));
        }
        let dq_ms = t_dq.elapsed().as_millis();

        // Elementwise add residual into the spectral f32 buffer. We rebuild
        // the byte stream from scratch (decode the spectral floats out, add,
        // re-encode) to avoid any unaligned-cast hazards inside Vec<u8>.
        debug_assert_eq!(spectral_bytes.len(), n_f32 * 4);
        let mut combined = vec![0u8; n_f32 * 4];
        for i in 0..n_f32 {
            let off = i * 4;
            let s = f32::from_le_bytes([
                spectral_bytes[off],
                spectral_bytes[off + 1],
                spectral_bytes[off + 2],
                spectral_bytes[off + 3],
            ]);
            let combined_val = s + resid_f32[i];
            let lb = combined_val.to_le_bytes();
            combined[off] = lb[0];
            combined[off + 1] = lb[1];
            combined[off + 2] = lb[2];
            combined[off + 3] = lb[3];
        }

        if dq_ms > 50 {
            eprintln!(
                "[GkqBackend] residual-add {} ({}×{}, dtype={}) +{} ms",
                name,
                raw.d_out,
                raw.d_in,
                tensor_type_from_code(resid.dtype_code),
                dq_ms
            );
        }
        Ok(combined)
    }
}

impl WeightBackend for GkqBackend {
    fn fetch_tensor(&self, name: &str) -> Result<OwnedBytes, String> {
        // Dense path: always-resident; cheap clone of the Arc.
        if let Some(arc) = self.dense_tensors.get(name) {
            return Ok(OwnedBytes::Owned(Arc::clone(arc)));
        }
        // Spectral path: cache hit?
        if let Some(raw) = self.spectral_raw.get(name) {
            {
                let mut cache = self.reconstruct_cache.lock();
                if let Some(arc) = cache.get(name) {
                    return Ok(OwnedBytes::Owned(arc));
                }
            }
            // Miss: do the work outside the lock (sgemm holds for ~100ms-2s).
            // For hybrid knots this also dequantizes + adds the residual.
            let t = std::time::Instant::now();
            let bytes = self.reconstruct_with_residual(name, raw)?;
            let elapsed_ms = t.elapsed().as_millis();
            // Only log slow ones (>50ms) so 0.5B inference doesn't spam.
            if elapsed_ms > 50 {
                let has_resid = self.residuals.contains_key(name);
                eprintln!(
                    "[GkqBackend] reconstruct {} ({}×{} rank={}, residual={}) in {} ms",
                    name, raw.d_out, raw.d_in, raw.rank, has_resid, elapsed_ms
                );
            }
            let arc = Arc::new(bytes);
            self.reconstruct_cache
                .lock()
                .put(name.to_string(), Arc::clone(&arc));
            return Ok(OwnedBytes::Owned(arc));
        }
        Err(format!("GkqBackend: missing tensor '{}'", name))
    }

    fn has_tensor(&self, name: &str) -> bool {
        self.dense_tensors.contains_key(name) || self.spectral_raw.contains_key(name)
    }

    fn prefetch(&self, names: &[String]) {
        // Background warm-up of likely-needed spectrals. Best-effort: if a
        // tensor is already cached or is dense, skip. Otherwise reconstruct
        // and insert. Sequential because matrixmultiply::sgemm is itself
        // multi-threaded internally.
        for name in names {
            if self.dense_tensors.contains_key(name) {
                continue;
            }
            let already_cached = self.reconstruct_cache.lock().get(name).is_some();
            if already_cached {
                continue;
            }
            if let Some(raw) = self.spectral_raw.get(name) {
                match self.reconstruct_with_residual(name, raw) {
                    Ok(bytes) => {
                        self.reconstruct_cache
                            .lock()
                            .put(name.clone(), Arc::new(bytes));
                    }
                    Err(e) => {
                        eprintln!(
                            "[GkqBackend] prefetch {} failed: {} (falling back to spectral-only)",
                            name, e
                        );
                        let bytes = raw.reconstruct();
                        self.reconstruct_cache
                            .lock()
                            .put(name.clone(), Arc::new(bytes));
                    }
                }
            }
        }
    }

    fn as_any(&self) -> &dyn std::any::Any {
        self
    }

    fn tensor_info(&self, name: &str) -> Option<TensorInfo> {
        self.metadata_map.get(name).cloned()
    }
}

// We never need `Read` on the imported `std::io::Read` symbol in this file,
// but keeping the import scoped here makes future header-extension work easier.
#[allow(dead_code)]
fn _ensure_read_in_scope() -> Option<Box<dyn Read>> {
    None
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_delta_decode_basic() {
        // The classic example from gkq_v2_format.py's smoke test.
        // Original: [10, 20, 15, 50, 5]
        // Encoded:  [10, 10, 251, 35, 211]  (deltas with wrap)
        let encoded = [10u8, 10, 251, 35, 211];
        let decoded = delta_decode(&encoded);
        assert_eq!(decoded, vec![10, 20, 15, 50, 5]);
    }

    #[test]
    fn test_delta_decode_empty() {
        let decoded = delta_decode(&[]);
        assert_eq!(decoded.len(), 0);
    }

    #[test]
    fn test_dequant_signed_endpoints() {
        // q=128 → 0 (the unsigned zero), q=0 → -max, q=255 → ~+max
        assert!((dequant_signed(128, 1.0)).abs() < 1e-6);
        assert!((dequant_signed(1, 1.0) + (127.0 / 127.0)).abs() < 1e-6);
    }

    #[test]
    fn test_dequant_unsigned_endpoints() {
        assert!(dequant_unsigned(0, 1.0).abs() < 1e-6);
        assert!((dequant_unsigned(255, 1.0) - 1.0).abs() < 1e-6);
    }

    #[test]
    fn test_translate_attn_o() {
        assert_eq!(
            translate_name("blk.0.attn_o.weight"),
            "blk.0.attn_output.weight"
        );
        assert_eq!(
            translate_name("blk.13.attn_o.bias"),
            "blk.13.attn_output.bias"
        );
        assert_eq!(translate_name("blk.0.attn_q.weight"), "blk.0.attn_q.weight");
        assert_eq!(translate_name("token_embd.weight"), "token_embd.weight");
    }
}
